23	/*
24	 * muconvert -- command line tool for converting documents
25	 */
26	
27	#include "mupdf/fitz.h"
28	
29	#include <stdlib.h>
30	#include <stdio.h>
31	
32	/* input options */
33	static const char *password = "";
34	static int alphabits = 8;
35	static float layout_w = FZ_DEFAULT_LAYOUT_W;
36	static float layout_h = FZ_DEFAULT_LAYOUT_H;
37	static float layout_em = FZ_DEFAULT_LAYOUT_EM;
38	static char *layout_user_css = NULL;
39	static char *layout_user_css_data = NULL;
40	static int layout_publisher_css = 1;
41	
42	/* output options */
43	static const char *output = NULL;
44	static const char *format = NULL;
45	static const char *options = "";
46	
47	static fz_context *ctx;
48	static fz_document *doc = NULL;
49	static fz_document_writer *out;
50	static fz_box_type page_box = FZ_CROP_BOX;
51	static int count;
52	
53	static int usage(void)
54	{
55		fprintf(stderr,
56			"Usage: mutool convert [options] file [pages]\n"
57			"\t-p -\tpassword\n"
58			"\n"
59			"\t-o -\toutput file name (%%d for page number)\n"
60			"\t-F -\toutput format (default inferred from output file name)\n"
61			"\t\t\traster: cbz, png, pnm, pgm, ppm, pam, pbm, pkm.\n"
62			"\t\t\tprint-raster: pcl, pclm, ps, pwg.\n"
63			"\t\t\tvector: pdf, svg.\n"
64			"\t\t\ttext: html, xhtml, text, stext.\n"
65			"\t-O -\tcomma separated list of options for output format\n"
66			"\n"
67			"\t-b -\tuse named page box (MediaBox, CropBox, BleedBox, TrimBox, or ArtBox)\n"
68			"\t-A -\tnumber of bits of antialiasing (0 to 8)\n"
69			"\t-W -\tpage width for EPUB layout\n"
70			"\t-H -\tpage height for EPUB layout\n"
71			"\t-S -\tfont size for EPUB layout\n"
72			"\t-U -\tfile name of user stylesheet for EPUB layout\n"
73			"\t-X\tdisable document styles for EPUB layout\n"
74			"\n"
75			"\tpages\tcomma separated list of page ranges (N=last page)\n"
76			"\n"
77			);
78		fputs(fz_draw_options_usage, stderr);
79		fputs(fz_pcl_write_options_usage, stderr);
80		fputs(fz_pclm_write_options_usage, stderr);
81		fputs(fz_pwg_write_options_usage, stderr);
82		fputs(fz_stext_options_usage, stderr);
83	#if FZ_ENABLE_PDF
84		fputs(fz_pdf_write_options_usage, stderr);
85	#endif
86		fputs(fz_svg_write_options_usage, stderr);
87		return 1;
88	}
89	
90	static void runpage(int number)
91	{
92		fz_rect box;
93		fz_page *page;
94		fz_device *dev = NULL;
95		fz_matrix ctm;
96	
97		page = fz_load_page(ctx, doc, number - 1);
98	
99		fz_var(dev);
100	
101		fz_try(ctx)
102		{
103			box = fz_bound_page_box(ctx, page, page_box);
104	
105			// Realign page box on 0,0
106			ctm = fz_translate(-box.x0, -box.y0);
107			box = fz_transform_rect(box, ctm);
108	
109			dev = fz_begin_page(ctx, out, box);
110			fz_run_page(ctx, page, dev, ctm, NULL);
111			fz_end_page(ctx, out);
112		}
113		fz_always(ctx)
114		{
115			fz_drop_page(ctx, page);
116		}
117		fz_catch(ctx)
118			fz_rethrow(ctx);
119	}
120	
121	static void runrange(const char *range)
122	{
123		int start, end, i;
124	
125		while ((range = fz_parse_page_range(ctx, range, &start, &end, count)))
126		{
127			if (start < end)
128				for (i = start; i <= end; ++i)
129					runpage(i);
130			else
131				for (i = start; i >= end; --i)
132					runpage(i);
133		}
134	}
135	
136	int muconvert_main(int argc, char **argv)
137	{
138		int i, c;
139		int retval = EXIT_SUCCESS;
140	
141		while ((c = fz_getopt(argc, argv, "p:A:W:H:S:U:Xo:F:O:b:")) != -1)
142		{
143			switch (c)
144			{
145			default: return usage();
146	
147			case 'p': password = fz_optarg; break;
148			case 'A': alphabits = atoi(fz_optarg); break;
149			case 'W': layout_w = fz_atof(fz_optarg); break;
150			case 'H': layout_h = fz_atof(fz_optarg); break;
151			case 'S': layout_em = fz_atof(fz_optarg); break;
152			case 'U': layout_user_css = fz_optarg; break;
153			case 'X': layout_publisher_css = 0; break;
154	
155			case 'o': output = fz_optpath(fz_optarg); break;
156			case 'F': format = fz_optarg; break;
157			case 'O': options = fz_optarg; break;
158	
159			case 'b':
160				page_box = fz_box_type_from_string(fz_optarg);
161				if (page_box == FZ_UNKNOWN_BOX)
162				{
163					fprintf(stderr, "Invalid box type: %s\n", fz_optarg);
164					return 1;
165				}
166				break;
167			}
168		}
169	
170		if (fz_optind == argc || (!format && !output))
171			return usage();
172	
173		/* Create a context to hold the exception stack and various caches. */
174		ctx = fz_new_context(NULL, NULL, FZ_STORE_UNLIMITED);
175		if (!ctx)
176		{
177			fprintf(stderr, "cannot create mupdf context\n");
178			return EXIT_FAILURE;
179		}
180	
181		/* Register the default file types to handle. */
182		fz_try(ctx)
183			fz_register_document_handlers(ctx);
184		fz_catch(ctx)
185		{
186			fz_report_error(ctx);
187			fprintf(stderr, "cannot register document handlers\n");
188			fz_drop_context(ctx);
189			return EXIT_FAILURE;
190		}
191	
192		fz_set_aa_level(ctx, alphabits);
193	
194		if (layout_user_css)
195			layout_user_css_data = fz_read_text_file(ctx, layout_user_css);
196	
197		/* Open the output document. */
198		fz_try(ctx)
199			out = fz_new_document_writer(ctx, output, format, options);
200		fz_catch(ctx)
201		{
202			fz_report_error(ctx);
203			fprintf(stderr, "cannot create document\n");
204			fz_drop_context(ctx);
205			return EXIT_FAILURE;
206		}
207	
208		fz_var(doc);
209		fz_try(ctx)
210		{
211			for (i = fz_optind; i < argc; ++i)
212			{
213				doc = fz_open_document(ctx, argv[i]);
214				if (fz_needs_password(ctx, doc))
215					if (!fz_authenticate_password(ctx, doc, password))
216						fz_throw(ctx, FZ_ERROR_ARGUMENT, "cannot authenticate password: %s", argv[i]);
217				fz_style_document(ctx, doc, layout_publisher_css, layout_user_css_data);
218				fz_layout_document(ctx, doc, layout_w, layout_h, layout_em);
219				count = fz_count_pages(ctx, doc);
220	
221				if (i+1 < argc && fz_is_page_range(ctx, argv[i+1]))
222					runrange(argv[++i]);
223				else
224					runrange("1-N");
225	
226				fz_drop_document(ctx, doc);
227				doc = NULL;
228			}
229			fz_close_document_writer(ctx, out);
230		}
231		fz_always(ctx)
232		{
233			fz_drop_document(ctx, doc);
234			fz_drop_document_writer(ctx, out);
235		}
236		fz_catch(ctx)
237		{
238			fz_report_error(ctx);
239			retval = EXIT_FAILURE;
240		}
241	
242		fz_free(ctx, layout_user_css_data);
243	
244		fz_drop_context(ctx);
245		return retval;
246	}
