283		if (is_extension(format, "odt"))
284			return fz_new_odt_writer_with_output(ctx, out, options);
285	#endif
286	#if FZ_ENABLE_DOCX_OUTPUT
287		if (is_extension(format, "docx"))
288			return fz_new_docx_writer_with_output(ctx, out, options);
289	#endif
290	
291		fz_throw(ctx, FZ_ERROR_ARGUMENT, "unknown output document format: %s", format);
292	}
293	
294	fz_document_writer *
295	fz_new_document_writer_with_buffer(fz_context *ctx, fz_buffer *buffer, const char *format, const char *options)
296	{
297		fz_document_writer *wri;
298		fz_output *out = fz_new_output_with_buffer(ctx, buffer);
299		fz_try(ctx) {
300			wri = fz_new_document_writer_with_output(ctx, out, format, options);
301		}
302		fz_catch(ctx) {
303			fz_drop_output(ctx, out);
304			fz_rethrow(ctx);
305		}
306		return wri;
307	}
308	
309	void
310	fz_close_document_writer(fz_context *ctx, fz_document_writer *wri)
311	{
312		if (wri->close_writer)
313			wri->close_writer(ctx, wri);
314		wri->close_writer = NULL;
315	}
316	
317	void
318	fz_drop_document_writer(fz_context *ctx, fz_document_writer *wri)
319	{
320		if (!wri)
321			return;
322	
323		if (wri->close_writer)
324			fz_warn(ctx, "dropping unclosed document writer");
325		if (wri->dev)
326			fz_drop_device(ctx, wri->dev);
327		if (wri->drop_writer)
328			wri->drop_writer(ctx, wri);
329		fz_free(ctx, wri);
330	}
331	
332	fz_device *
333	fz_begin_page(fz_context *ctx, fz_document_writer *wri, fz_rect mediabox)
334	{
335		if (!wri)
336			return NULL;
337		if (wri->dev)
338			fz_throw(ctx, FZ_ERROR_ARGUMENT, "called begin page without ending the previous page");
339		wri->dev = wri->begin_page(ctx, wri, mediabox);
340		return wri->dev;
341	}
342	
343	void
344	fz_end_page(fz_context *ctx, fz_document_writer *wri)
345	{
346		fz_device *dev;
347	
348		if (!wri)
349			return;
350		dev = wri->dev;
351		wri->dev = NULL;
352		wri->end_page(ctx, wri, dev);
353	}
354	
355	void
356	fz_write_document(fz_context *ctx, fz_document_writer *wri, fz_document *doc)
357	{
358		int i, n;
359		fz_page *page = NULL;
360		fz_device *dev;
361	
362		fz_var(page);
363	
364		n = fz_count_pages(ctx, doc);
365		fz_try(ctx)
366		{
367			for (i = 0; i < n; i++)
368			{
369				page = fz_load_page(ctx, doc, i);
370				dev = fz_begin_page(ctx, wri, fz_bound_page(ctx, page));
371				fz_run_page(ctx, page, dev, fz_identity, NULL);
372				fz_drop_page(ctx, page);
373				page = NULL;
374				fz_end_page(ctx, wri);
375			}
376		}
377		fz_catch(ctx)
378		{
379			fz_drop_page(ctx, page);
380			fz_rethrow(ctx);
381		}
382	}
